insert into lessons (id, unit_id, order_index, title, description, type, xp_reward) values
 ('40000000-0000-0000-0000-000000001301','30000000-0000-0000-0000-000000000013',1,$p$¿Alguna vez lo has hecho?$p$,$p$¿Alguna vez lo has hecho?$p$,'lesson',15),
 ('40000000-0000-0000-0000-000000001302','30000000-0000-0000-0000-000000000013',2,$p$Just, already y yet$p$,$p$Just, already y yet$p$,'lesson',15),
 ('40000000-0000-0000-0000-000000001303','30000000-0000-0000-0000-000000000013',3,$p$Desde hace cuánto: for y since$p$,$p$Desde hace cuánto: for y since$p$,'lesson',15),
 ('40000000-0000-0000-0000-000000001304','30000000-0000-0000-0000-000000000013',4,$p$Antes y ahora: used to y pasado simple$p$,$p$Antes y ahora: used to y pasado simple$p$,'lesson',15),
 ('40000000-0000-0000-0000-000000001305','30000000-0000-0000-0000-000000000013',5,$p$🏁 Checkpoint Unidad 13$p$,$p$En esta unidad practicas el present perfect (have/has + participio) para hablar de experiencias y de acciones recientes, con just (justo/recién), already (ya) y yet (todavía / ya, en negativas y preguntas), y con for (durante) y since (desde). Contrastas el pasado simple (momento terminado y conocido: yesterday, last week, ago) con el present perfect (experiencia o pasado sin tiempo concreto), y usas used to para hablar de hábitos y estados del pasado que ya no ocurren.$p$,'checkpoint',40)
on conflict (unit_id, order_index) do update set title=excluded.title, description=excluded.description;
