insert into lessons (id, unit_id, order_index, title, description, type, xp_reward) values
 ('40000000-0000-0000-0000-000000001401','30000000-0000-0000-0000-000000000014',1,$p$Buscar y solicitar trabajo$p$,$p$Buscar y solicitar trabajo$p$,'lesson',15),
 ('40000000-0000-0000-0000-000000001402','30000000-0000-0000-0000-000000000014',2,$p$El primer día y las tareas$p$,$p$El primer día y las tareas$p$,'lesson',15),
 ('40000000-0000-0000-0000-000000001403','30000000-0000-0000-0000-000000000014',3,$p$Estudios y formación$p$,$p$Estudios y formación$p$,'lesson',15),
 ('40000000-0000-0000-0000-000000001404','30000000-0000-0000-0000-000000000014',4,$p$Planes de futuro y decisiones$p$,$p$Planes de futuro y decisiones$p$,'lesson',15),
 ('40000000-0000-0000-0000-000000001405','30000000-0000-0000-0000-000000000014',5,$p$🏁 Checkpoint Unidad 14$p$,$p$En esta unidad practicas el primer condicional (if + presente simple, will + verbo) para hablar de consecuencias reales en el trabajo y los estudios; introduces el present perfect continuous (have/has been + verbo-ing) para acciones que empezaron en el pasado y siguen ahora; y distingues 'be going to' (planes y decisiones ya tomadas) de 'will' (decisiones del momento, predicciones y ofrecimientos). Todo con léxico de trabajo, estudios y planes de futuro.$p$,'checkpoint',40)
on conflict (unit_id, order_index) do update set title=excluded.title, description=excluded.description;
