insert into lessons (id, unit_id, order_index, title, description, type, xp_reward) values
 ('40000000-0000-0000-0000-000000001501','30000000-0000-0000-0000-000000000015',1,$p$Dar tu opinión$p$,$p$Aprende a introducir tu opinión de forma natural.$p$,'lesson',15),
 ('40000000-0000-0000-0000-000000001502','30000000-0000-0000-0000-000000000015',2,$p$Estoy de acuerdo, yo también$p$,$p$Expresa que tú también, de forma corta y natural.$p$,'lesson',15),
 ('40000000-0000-0000-0000-000000001503','30000000-0000-0000-0000-000000000015',3,$p$Tampoco estoy de acuerdo$p$,$p$Aprende a decir que tú tampoco y a mostrar desacuerdo.$p$,'lesson',15),
 ('40000000-0000-0000-0000-000000001504','30000000-0000-0000-0000-000000000015',4,$p$Contar lo que otros dijeron$p$,$p$Reporta opiniones de otras personas y conecta tus ideas.$p$,'lesson',15),
 ('40000000-0000-0000-0000-000000001505','30000000-0000-0000-0000-000000000015',5,$p$🏁 Checkpoint Unidad 15$p$,$p$En esta unidad practicas dar opiniones (I think/believe that…, In my opinion…), expresar acuerdo y desacuerdo con So do I / Neither do I (y So am I / Neither am I), introducir lo que otra persona dijo con estilo indirecto (He said that…, She told me that…) y unir ideas con conectores (because, although, however, so). Umbral 80%.$p$,'checkpoint',40)
on conflict (unit_id, order_index) do update set title=excluded.title, description=excluded.description;
