insert into lessons (id, unit_id, order_index, title, description, type, xp_reward) values
 ('40000000-0000-0000-0000-000000001601','30000000-0000-0000-0000-000000000016',1,$p$El comienzo del viaje$p$,$p$El comienzo del viaje$p$,'lesson',15),
 ('40000000-0000-0000-0000-000000001602','30000000-0000-0000-0000-000000000016',2,$p$Lo que pasaba mientras...$p$,$p$Lo que pasaba mientras...$p$,'lesson',15),
 ('40000000-0000-0000-0000-000000001603','30000000-0000-0000-0000-000000000016',3,$p$La gente y los lugares del viaje$p$,$p$La gente y los lugares del viaje$p$,'lesson',15),
 ('40000000-0000-0000-0000-000000001604','30000000-0000-0000-0000-000000000016',4,$p$Una anécdota inolvidable$p$,$p$Una anécdota inolvidable$p$,'lesson',15),
 ('40000000-0000-0000-0000-000000001605','30000000-0000-0000-0000-000000000016',5,$p$🏁 Checkpoint Unidad 16$p$,$p$En esta unidad narras en pasado y hablas de viajes. Usas el pasado simple para acciones terminadas y el pasado continuo (was/were + -ing) para acciones en progreso, combinándolos con 'while' (acción larga) y 'when' (acción que interrumpe). También describes personas, cosas y lugares con cláusulas relativas: 'who' para personas, 'which' para cosas y 'that' para ambos.$p$,'checkpoint',40)
on conflict (unit_id, order_index) do update set title=excluded.title, description=excluded.description;
