insert into lessons (id, unit_id, order_index, title, description, type, xp_reward) values
 ('40000000-0000-0000-0000-000000001701','30000000-0000-0000-0000-000000000017',1,$p$Cuando algo se rompe$p$,$p$Cuando algo se rompe$p$,'lesson',15),
 ('40000000-0000-0000-0000-000000001702','30000000-0000-0000-0000-000000000017',2,$p$Si pasa esto, haré aquello$p$,$p$Si pasa esto, haré aquello$p$,'lesson',15),
 ('40000000-0000-0000-0000-000000001703','30000000-0000-0000-0000-000000000017',3,$p$Reglas, avisos y obligaciones$p$,$p$Reglas, avisos y obligaciones$p$,'lesson',15),
 ('40000000-0000-0000-0000-000000001704','30000000-0000-0000-0000-000000000017',4,$p$Pedir ayuda y dar consejo$p$,$p$Pedir ayuda y dar consejo$p$,'lesson',15),
 ('40000000-0000-0000-0000-000000001705','30000000-0000-0000-0000-000000000017',5,$p$🏁 Checkpoint Unidad 17$p$,$p$En esta unidad practicas cómo describir problemas cotidianos y proponer soluciones. Usas el condicional cero (If + presente, presente) para verdades y normas, y el condicional primero (If + presente, will + verbo) para consecuencias probables. Además dominas los modales: must y have to (obligación), mustn't y can't (prohibición), y should/shouldn't (consejo), para dar instrucciones, advertencias y recomendaciones al resolver averías, retrasos, errores y emergencias.$p$,'checkpoint',40)
