insert into lessons (id, unit_id, order_index, title, description, type, xp_reward) values
 ('40000000-0000-0000-0000-000000001801','30000000-0000-0000-0000-000000000018',1,$p$How things are made$p$,$p$How things are made$p$,'lesson',15),
 ('40000000-0000-0000-0000-000000001802','30000000-0000-0000-0000-000000000018',2,$p$Famous places and the past$p$,$p$Famous places and the past$p$,'lesson',15),
 ('40000000-0000-0000-0000-000000001803','30000000-0000-0000-0000-000000000018',3,$p$Comparing films and media$p$,$p$Comparing films and media$p$,'lesson',15),
 ('40000000-0000-0000-0000-000000001804','30000000-0000-0000-0000-000000000018',4,$p$Dreams and the future$p$,$p$Dreams and the future$p$,'lesson',15),
 ('40000000-0000-0000-0000-000000001805','30000000-0000-0000-0000-000000000018',5,$p$🏁 Checkpoint Unidad 18$p$,$p$En esta unidad practicas la voz pasiva en presente y pasado (is made / was built) para hablar de cómo se crean y producen las cosas, el segundo condicional (If I had…, I would…) para imaginar situaciones y sueños hipotéticos, y los comparativos avanzados con as…as y not as…as para comparar películas, medios y experiencias. Todo en el contexto de cultura, medios de comunicación y planes de futuro.$p$,'checkpoint',40)
